function AjvCompiler (opts) {
  const validatorPool = new Map()
  const serializerPool = new Map()

  if (opts && opts.jtdSerializer === true) {
    return function buildSerializerFromPool (externalSchemas, serializerOpts) {
      const uniqueAjvKey = getPoolKey({}, serializerOpts)
      if (serializerPool.has(uniqueAjvKey)) {
        return serializerPool.get(uniqueAjvKey)
      }

      const compiler = new SerializerCompiler(externalSchemas, serializerOpts)
      const ret = compiler.buildSerializerFunction.bind(compiler)
      serializerPool.set(uniqueAjvKey, ret)

      return ret
    }
  }

  return function buildCompilerFromPool (externalSchemas, options) {
    const uniqueAjvKey = getPoolKey(externalSchemas, options.customOptions)
    if (validatorPool.has(uniqueAjvKey)) {
      return validatorPool.get(uniqueAjvKey)
    }

    const compiler = new ValidatorCompiler(externalSchemas, options)
    const ret = compiler.buildValidatorFunction.bind(compiler)
    validatorPool.set(uniqueAjvKey, ret)

    if (options.customOptions.code !== undefined) {
      ret[AjvReference] = compiler
    }

    return ret
  }
}

async function decorateFastifyInstance (fastify) {
  const db = fastify.mongo.db

  const userCollection = await db.createCollection('users')
  const userService = new UserService(userCollection)
  await userService.ensureIndexes(db)
  fastify.decorate('userService', userService)

  const tweetCollection = await db.createCollection('tweets')
  const tweetService = new TweetService(tweetCollection)
  await tweetService.ensureIndexes(db)
  fastify.decorate('tweetService', tweetService)

  const followService = new FollowService(fastify.redis)
  fastify.decorate('followService', followService)

  const timelineService = new TimelineService(followService, tweetService)
  fastify.decorate('timelineService', timelineService)

  fastify.decorate('authPreHandler', async function auth (request, reply) {
    try {
      await request.jwtVerify()
    } catch (err) {
      reply.send(err)
    }
  })

  fastify.decorate('transformStringIntoObjectId', transformStringIntoObjectId)
}

function comparePathsObjects (ctx, sourcePathsObjects, targetPathsObjects) {
  const { sameKeys, addedKeys, removedKeys } = compareObjectKeys(
    sourcePathsObjects,
    targetPathsObjects
  )

  for (const path of addedKeys) {
    const pathSchema = targetPathsObjects[path]
    // TODO: check for $ref here
    for (let method of Object.keys(pathSchema)) {
      method = method.toLocaleLowerCase()
      if (!HTTP_METHODS.includes(method)) continue
      const operationSchema = pathSchema[method]
      ctx.addedOperations.push({
        method,
        path,
        targetSchema: operationSchema
      })
    }
  }

  for (const path of removedKeys) {
    const pathSchema = sourcePathsObjects[path]
    // TODO: check for $ref here
    for (let method in pathSchema) {
      method = method.toLocaleLowerCase()
      if (!HTTP_METHODS.includes(method)) continue
      const operationSchema = pathSchema[method]
      ctx.deletedOperations.push({
        method,
        path,
        sourceSchema: operationSchema
      })
    }
  }

  for (const path of sameKeys) {
    const sourcePathObject = sourcePathsObjects[path]
    const targetPathObject = targetPathsObjects[path]
    // TODO: check for $ref here
    comparePathObjects(ctx, path, sourcePathObject, targetPathObject)
  }
}

export async function updateUndiciInterceptors (undiciConfig) {
  const updatableInterceptors = globalThis[kInterceptors]
  if (!updatableInterceptors) return

  if (Array.isArray(undiciConfig?.interceptors)) {
    for (const interceptorConfig of undiciConfig.interceptors) {
      const { module, options } = interceptorConfig

      const interceptorCtx = updatableInterceptors[module]
      if (!interceptorCtx) continue

      const { createInterceptor, updateInterceptor } = interceptorCtx
      updateInterceptor(createInterceptor(options))
    }
  } else {
    for (const key of ['Agent', 'Pool', 'Client']) {
      const interceptorConfigs = undiciConfig.interceptors[key]
      if (!interceptorConfigs) continue

      for (const interceptorConfig of interceptorConfigs) {
        const { module, options } = interceptorConfig

        const interceptorCtx = updatableInterceptors[key][module]
        if (!interceptorCtx) continue

        const { createInterceptor, updateInterceptor } = interceptorCtx
        updateInterceptor(createInterceptor(options))
      }
    }
  }
}

export function generateProjectData(data) {
	const { project, projectDir, testDir, config, specification, localPlugin } =
		data;
	const specFile = "openApi.json";
	const serviceFile = "service.js";
	const securityFile = "security.js";
	const plugin = "index.js";
	const pluginPackageName = localPlugin
		? pathLocal(projectDir, plugin)
		: data.pluginPackageName;
	const instructions = generateInstructions();
	const files = {
		spec: contents(
			projectDir,
			specFile,
			JSON.stringify(specification, null, "\t"),
		),
		service: contents(projectDir, serviceFile, generateService(config)),
		security: contents(projectDir, securityFile, generateSecurity(config)),
		plugin: contents(
			projectDir,
			plugin,
			generatePlugin({
				specFile,
				serviceFile,
				securityFile,
				pluginPackageName,
			}),
		),
		readme: contents(
			projectDir,
			"README.md",
			generateReadme(project, instructions),
		),
		testPlugin: contents(
			testDir,
			"test-plugin.js",
			generateTest(Object.assign(config, { specFile, serviceFile, plugin })),
		),
	};
	return { files, pkgTemplate, instructions };
}
